def rwsa(text) -> str:
    normal_alphabet = "AĄÄBCĆDEĘFGHIJKLŁMNOÖÒÓPQRSŚTUÜVWXYZŻŹ" + "aąäbcćdeęfghijklłmnoöòópqrsśtuüvwxyzżź" + "1234567890" # + '+-=()'
    special_alphabet1 = "ᴀᴀᴀʙᴄᴄᴅᴇᴇꜰɢʜɪᴊᴋʟʟᴍᴎᴏᴏᴏᴏᴘǫʀssᴛᴜᴜᴠᴡxʏᴢzᴢ" + "ᴀᴀᴀʙᴄᴄᴅᴇᴇꜰɢʜɪᴊᴋʟʟᴍᴎᴏᴏᴏᴏᴘǫʀssᴛᴜᴜᴠᴡxʏᴢzz" + f"{'1234567890' if os.name == 'nt' else '𝟷𝟸𝟹𝟺𝟻𝟼𝟽𝟾𝟿𝟶'}" # + '₊ ₋ ₌ ₍ ₎'
    special_alphabet2 = 'ᴬᴬᴬᴮᶜᶜᴰᴱᴱᶠᴳᴴᴵᴶᴷᴸᴸᴹᴺᴼᴼᴼᴼᴾᵠᴿˢˢᵀᵁᵁⱽᵂˣʸᶻᶻᶻ' + 'ᵃᵃᵃᵇᶜᶜᵈᵉᵉᶠᵍʰⁱʲᵏˡˡᵐⁿᵒᵒᵒᵒᵖᵠʳˢˢᵗᵘᵘᵛʷˣʸᶻᶻᶻ' + '¹²³⁴⁵⁶⁷⁸⁹⁰' # + '⁺⁻⁼⁽⁾'
    translation_table = str.maketrans(normal_alphabet, special_alphabet1)
    return text.translate(translation_table)

def print_colored(text: str, color: str) -> None:
    colors: Dict[str, str] = {"green": f"{GREEN}", "red": f"{RED}", "blue": f"{BLUE}", "yellow": f"{GOLD}", "cyan": f"{CYAN}", "magenta": f"{MAGENTA}"}
    color_code: str = colors.get(color.lower(), f"{RESET}")
    colored_text: str = f"{color_code}{rwsa(text)}{RESET}"
    print(colored_text)

