def parse_and_format_time_string(time_str):
    if time_str == "Unlimited": return time_str
    formats = ['%b %d, %Y, %I:%M %p', '%B %d, %Y %H:%M', '%b %d, %Y', '%B %d, %Y, %I:%M %p']
    for fmt in formats:
        try:
            date_obj = datetime.strptime(time_str, fmt)
            return rwsa(date_obj.strftime("%d.%b.%Y  %H:%M"))
        except ValueError: continue
    return rwsa(time_str)

def get_country_from_ip_online(ip_address, timeout: int = 6):
    try:
        headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 6.1; rv:80.0) Gecko/20100101 Firefox/80.0'}
        response = requests.get(f'http://ipinfo.io/{ip_address}/json', headers=headers, timeout=timeout, allow_redirects=False)
        data = response.json()
        return data.get('region', 'Uɴᴋɴᴏᴡɴ'), data.get('city', 'Uɴᴋɴᴏᴡɴ'), data.get('country', 'Uɴᴋɴᴏᴡɴ')
    except (requests.RequestException) as e: print("\033[91m        {sp_sym} Vᴘɴ ᴅᴏɴᴛ ᴡᴏʀᴋɪɴɢ, Exɪᴛɪɴɢ {sp_sym}    ")

def ist_valide_url(url):
    return bool(re.match(r'^https?://[^\s/$.?#].[^\s]*$', url))

def get_base_url(base_url: str) -> str:
    global parsed_url
    parsed_url = urlparse(base_url)
    host = parsed_url.hostname
    port = parsed_url.port
    if port is None: port = 80
    return f"http://{host}:{port}"

def cloud_check(base_url, timeout=4):
    global cloud_flare, san_host
    isp_check_urls = ['http://ip-api.com/json/']
#            'http://freegeoip.app/json/',
#            'http://ipapi.co/'
        
    for isp_check_url in isp_check_urls:
        try:
            san_host = urlparse(base_url).hostname
            loc_session = requests.Session()
            data = loc_session.get(f"{isp_check_url}{san_host}", timeout=timeout).json()
            loc_session.close()
        except requests.RequestException: data = {}; continue
        loc_session.close()
        cloud_flare = data.get("isp", 'Uɴᴋɴᴏᴡɴ')
        if cloud_flare != 'Uɴᴋɴᴏᴡɴ': break
        
def get_token_expiry(session: requests.Session, base_url: str, timeout: int = 9) -> Tuple[bool, Optional[str], Optional[str]]:
    global count_good_portal, count_bad_portal, rescode
    url = f"{base_url}/portal.php?action=handshake&type=stb&token=&JsHttpRequest=1-xml"
    try:
        headers = {
            "User-Agent": "Mozilla/5.0 (compatible; CloudFlare-AlwaysOnline/1.0; +https://www.cloudflare.com/always-online) AppleWebKit/534.34 (KHTML, like Gecko) MAG200 stbapp ver: 2 rev: 250 Safari/534.34",
            "Accept": "application/json,application/javascript,text/javascript,text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
            "Accept-Encoding": "gzip, deflate",
            "Connection": "Keep-Alive",
            "Cookie": f"mac={mac}; stb_lang=en;",
            "X-User-Agent": "Model: MAG254; Link: Ethernet",
            "NEL": '{"success_fraction":0,"report_to":"cf-nel","max_age":604800}',
            "Pragma": "no-cache",
            "Server": "cloudflare",
            "x-proxy-cache": "MISS",
            "Report-To": '{"endpoints":[{"url":"https:\\/\\/a.nel.cloudflare.com\\/report\\/v3?s=aD7S2OF4niZxQQzkOWJyzBIqVylHQbmf9jFKrVx4L3DDOpbjYyq0DZTg9ZB9PhLhDT19R3axPLdnzGgGL%2BYcygkCBA7%2BcPBLf0%2FtCwZGzIawMJ5GBh%2Bih57Y4vtrdg%3D%3D"}],"group":"cf-nel","max_age":604800}',
        }
        res = session.get(url, timeout=timeout, headers=headers, allow_redirects=False)
        count_good_portal += 1
        rescode = res.status_code
        data = json.loads(res.text)
        token = data['js']['token']
        session.cookies.update({'mac': f'{mac}', 'token': f'{token}'})
        url = f"{base_url}/portal.php?type=account_info&action=get_main_info&JsHttpRequest=1-xml"
        headers = {
            "Authorization": f"Bearer {token}",
            "User-Agent": "Mozilla/5.0 (QtEmbedded; U; Linux; C) AppleWebKit/533.3 (KHTML, like Gecko) MAG200 stbapp ver: 2 rev: 234 Safari/533.3"
        }
        res = session.get(url, headers=headers, timeout=timeout, allow_redirects=False)
        rescode = res.status_code
        data = json.loads(res.text)
        expiry = data['js']['phone']
        expiry = parse_and_format_time_string(expiry)
        return True, token, expiry
    except (requests.RequestException) as e:
        if isinstance(e, (requests.ConnectionError, requests.Timeout)): rescode = 503; count_bad_portal += 1
        if isinstance(e, (requests.HTTPError, requests.TooManyRedirects)): rescode = str(e.response.status_code); count_good_portal += 1
        return False, None, None
    except (json.JSONDecodeError, KeyError) as e: return True, None, None

def fetch_and_filter_chan(session: requests.Session, base_url: str, token: str) -> Optional[str]:
    url_genre = f"{base_url}/server/load.php?type=itv&action=get_genres&JsHttpRequest=1-xml"
    pento = "𖤐"
    bez_hit = f"⭒ 🌍 ⭒" if mini_hit == 0 else f"{pento}\n│ {pento} Bᴇᴢ Pᴏʟsᴋɪᴄʜ ʟᴜʙ Nɪᴇᴍɪᴇᴄᴋɪᴄʜ ᴋᴀɴᴀʟᴏᴡ" if mini_hit in (1, 2) else f" ⭒ 🌍 ⭒"
    filter_headers = {
        "Authorization": f"Bearer {token}",
        "User-Agent": "Mozilla/5.0 (QtEmbedded; U; Linux; C) AppleWebKit/533.3 (KHTML, like Gecko) MAG200 stbapp ver: 2 rev: 234 Safari/533.3"
    }
    cookies = {'mac': mac, 'token': token}
    try:
        group_info = {group['id']: f"{pento} {group['title']}" for group in session.get(url_genre, headers=filter_headers, cookies=cookies, timeout=15).json().get('js', [])}
        if not group_info: return bez_hit
        if mini_hit == 2: return f"{pento}\n│ {rwsa(' '.join(group_info.values()).translate(str.maketrans('', '', ',{}')).strip())}"
        de_patterns = ["DE -", "DE|", "✴DE ", "DE |", "DE  |", "DE ⋅", "de|", "DE ⬤", "Alemanha", "DEUTSCH", "DE •", "DE┃", '"de: ', '"DE: ', f"{pento} DE: ", "DE :", "DE.|", '"DE ', "ALEMAN", "German", "GERMAN", "DE]", "DE)", "DE-",  "DE✦", "DE ✦", "- DE ", "⋆ DE", f"{pento} DE", "DE  ", f"{pento} DEU", "german", "deutsch"]
        pl_patterns = ["PL -", "PL|", "✴PL ", "PL |", "PL  |", "PL ⋅", "pl|", "PL ⬤", "POLON", "Poland", "Polish", "POLISH", "POLAND", "PL •", "PL┃", '"PL: ', f"{pento} PL: ", '"pl: ', "POL |", "PL.|", f"{pento} PL :", "PL • ", '"PL ', "POLÔNIA", "PL]", "PL)", "Polonia", "PL-", "PL✦", "PL ✦", "- PL ", "⋆ PL", "POLSKA", f"{pento} PL", "PL  ", f"{pento} POL", "polish", "polska", "Polska"]
        in_patterns = ["IN - ", "IN|", "✴IN ", "IN |", "IN  |", "ind|", "IND|", "IN]", "IND]", "HINDI", "IND   |", "IN   |", "IN ⬤", "Hindi", "Punjabi", "Bengali", "Tamil", "Telugu", "Malayalam", "Kannada", "Gujarati", "India", "INDIA", "PUNJABI", "KANNADA", "MALAYALAM", "MARATHI", "TAMIL", "GUJARATI", "TELUGU", "BHOJPURI", "URDU", "india", "punjabi"]
        pattern_regex = re.compile("|".join(map(re.escape, de_patterns + pl_patterns + in_patterns)))
        filtered_matches = [value for value in group_info.values() if pattern_regex.search(value)]
        if not filtered_matches: return bez_hit
        extracted_strings = ' '.join(filtered_matches).replace(',', '').strip()
        extracted_strings = re.sub(rf'({pento} DEN[^{pento}]*{pento})+', pento, extracted_strings)
        extracted_strings = re.sub(rf'{pento}\s+{pento}', pento, extracted_strings)
        if mini_hit == 1: return f"{pento}\n│ {rwsa(extracted_strings)}"
        if mini_hit == 0:
            flags = [(any(p in extracted_strings for p in patterns), emoji) for patterns, emoji in [(de_patterns, "🇩🇪"), (pl_patterns, "🇵🇱"), (in_patterns, "🇮🇳")]]
            return f"⭒ {' ⋆ '.join(emoji for has_flag, emoji in flags if has_flag)} ⭒" if any(has_flag for has_flag, _ in flags) else bez_hit
    except (requests.RequestException, json.JSONDecodeError) as e: return bez_hit

