def process_mac_address(session, base_url: str) -> None:
    set_title_name(f"Multi-Portal-MAC-Scan | {mac} | Hit: ({count_hit_chan}) | Good: {count_good_portal} | Bad: {count_bad_portal} | Now: {count_current_portal}")
    try:
        sanitized_base_url = get_base_url(base_url)
        success, token, expiry = get_token_expiry(session, sanitized_base_url)
        if success and (token and expiry):
            with lock: save_channel_list(session, sanitized_base_url, expiry, token)
        if success and not (token or expiry):
            with lock:
                token_str = f"  \n├◉ 𖤐 ᴛᴏᴋᴇɴ: {token} 𖤐    " if token else '   '
                print_colored(f"├─◉ {count_current_portal} 𖤐 {base_url} 𖤐 ᴄᴏᴅᴇ: {rescode} 𖤐 {token_str}", "yellow")
        elif not success:
            with lock: print_colored(f"├─◉ {count_current_portal} 𖤐 {base_url} 𖤐 ᴄᴏᴅᴇ: {rescode} 𖤐 ", "magenta")
    except Exception as e: pass

def worker(base_url: str) -> None:
    global count_current_portal
    session = requests.Session()
    session.cookies.update({'mac': mac})
    with lock: count_current_portal += 1
    process_mac_address(session, base_url)
    session.close()

