def main():
    global mac, txt_file_path, ordner_name
    try:
        print(f"{LOGO}")
        count_url = len(urls_vollstaendig)
        print_colored(f"\n\n      Portals: {count_url}\n", "blue")
        # ⒈⒉⒊⒋⒌⒍⒎⒏⒐⒑⒒⒓⒔⒕⒖⒗⒘⒙⒚⒛
        user_input = input(f"{GRAY}\n      ⒈{PENTA} ᔑᑕᗩᑎ ᗰᗩᑕ    \n\n      ⒏  {ORANGE}ᖇᗕᒪᗜᗅᐃ {DOTB} • {RESET}{GRAY}⒐  {RED}ᗕ᙭ᔫᖶ  \n\n\n        {PENTA}:  {RESET}") or '1'
        if not user_input in ('1','9','8'): restart_script()
        if user_input == '8': restart_script()
        if user_input == '9': exit(0)
        if user_input == '1':
            mac_input = input(f'\n\n        {PENTA}Enter {"MAC" if os.name == "nt" else "𝕄𝔸ℂ"}: {RESET}') or '00:1A:79:00:00:00'
            mac = (re.search(r'([0-9A-Fa-f]{2}(?::[0-9A-Fa-f]{2}){5})', mac_input) or ['00:1A:79:00:00:00']).group(1)
        set_title_name(f"Multi-Portal-MAC-Scan | {mac} | ({count_hit_chan})")
        sanitize_txt_filename = mac.replace(":", "-")
        sanitized_txt_filename = f'HIT-𝕄𝔸ℂ-𝕊𝕔𝕒𝕟_{sanitize_txt_filename}'
        start_time, current_time, current_date = f'{time.strftime("%H:%M")}-{time.strftime("%m.%d.%Y")}', time.strftime("%H-%M"), time.strftime("%m-%d-%Y")
        san_current_time_date = rwsa(f"{current_date}⭒{current_time}")
        print(f"\n\n      {GRAY}{rwsa('Start')}: {GOLD}{rwsa(start_time)}")
        txt_file_name = f'{sanitized_txt_filename}_{san_current_time_date}.txt'
        txt_file_path = os.path.join(ordner_name, txt_file_name)
        with open(txt_file_path, 'w', encoding="utf-8") as txt_file:
            txt_file.write(LOGO.translate(str.maketrans('', '', '\x1b[38;5;33m\x1b[38;5;31m\x1b[38;5;102m\x1b[38;5;202m')).replace("       ",""))
            txt_file.write(f"\n\n                 𖤐 `{mac}` 𖤐\n")
            txt_file.write(f"\n\n╭─✠ sᴄʀɪᴘᴛ ᴘʏ ʙʏ {AUTHOR} ✠")
        print_colored(f"\n\n╭─◉ 𖤐 {mac} 𖤐    \n│\n├─◉ⒷⒶⓈⒺⓊⓇⓁ─○○      ", "blue")
        process_macs_in_threads()
        print_colored(f"│\n╰◉ 𖤐 {count_url} sᴄᴀɴɴᴇᴅ ᴘᴏʀᴛᴀʟs ⭒ {count_hit_chan} ʜɪᴛs 𖤐    \n\n", "blue")
        end_time = f'{time.strftime("%H:%M")}-{time.strftime("%m.%d.%Y")}'
        print(f"""
            
        ⚙️ {GRAY} {rwsa('Start')} ⋆ \t{GOLD}{rwsa(start_time)}   {GREEN}
        ╰» {GOLD}{rwsa('End')} ⋆ \t{GOLD}{rwsa(end_time)}    {RESET}

        ⚙️ {GRAY} {rwsa('Portal Stats ⋆ Scanned')} ⋆ {ORANGE}{rwsa(str(count_current_portal))}  {GREEN}
        ╰» {GOLD}{rwsa('Good')}: {GREEN}{rwsa(str(count_good_portal))} ⋆ {GOLD}{rwsa('Bad')}: {RED}{rwsa(str(count_bad_portal))} ⋆ {GOLD}{rwsa('Hits')}: {BLUE}{rwsa(str(count_hit_chan))}    {RESET}
""")
        with open(txt_file_path, 'a') as txt_file: txt_file.write(f"\n│\n╰◉ 𖤐 {rwsa(str(count_url))} sᴄᴀɴɴᴇᴅ ᴘᴏʀᴛᴀʟs ⭒ {rwsa(str(count_hit_chan))} ʜɪᴛs 𖤐")
        time.sleep(6.66)
        dalej()
    except KeyboardInterrupt: print_colored(f"\n╭─◉🄴🅁🅁🄾🅁─○○      \n╰◉ ⍟ Exiting gracefully ⍟     \n\n", "red"); restart_script()
    except ValueError as e: print(f"main: {e}")

